     2→ * MMS Data Types
     3→ *
     4→ * Architecture: Persistence vs Rendering
     5→ *
     6→ * Data flows through two distinct layers:
     7→ *
     8→ * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
     9→ *   startDate: string      (Date objects)       startDay: 74
    10→ *   "2024-03-15"           for logic            trainIndex: 5
    11→ *
    12→ * Why this separation?
    13→ * - Date objects cannot be serialized to JSON (become {})
    14→ * - Canvas needs numeric offsets for position calculations
    15→ * - Domain logic needs semantic dates for business rules
    16→ */
    17→
    18→// ─────────────────────────────────────────────────────────────
    19→// ENUMS & CONSTANTS
    20→// ─────────────────────────────────────────────────────────────
    21→
    22→export type AssetType = 'ALSTOM' | 'KINKI';
    23→export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
    24→export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';
    25→
    26→// ─────────────────────────────────────────────────────────────
    27→// DOMAIN TYPES (Persistent/Serializable)
    28→// These types can be saved to JSON, sent via API, or stored in localStorage.
    29→// ─────────────────────────────────────────────────────────────
    30→
    31→export interface Train {
    32→  id: string;              // "TRAIN-001" or "ALT-001"
    33→  name: string;            // Display name
    34→  assetType: AssetType;    // Fleet type
    35→}
    36→
    37→export interface Task {
    38→  id: string;              // Unique identifier
    39→  trainId: string;         // Reference to Train.id
    40→  startDate: string;       // ISO 8601 date: "2024-03-15"
    41→  endDate: string;         // ISO 8601 date: "2024-03-20"
    42→  type: TaskType;          // Visual category
    43→  hasConflict: boolean;    // Conflict indicator
    44→}
    45→
    46→export interface DatasetMeta {
    47→  startDate: string;       // ISO 8601: "2024-01-01"
    48→  trainCount: number;      // Number of trains
    49→  years: number;           // Time range in years
    50→}
    51→
    52→export interface GeneratedData {
    53→  trains: Train[];
    54→  tasks: Task[];
    55→  meta: DatasetMeta;
    56→}
    57→
    58→// ─────────────────────────────────────────────────────────────
    59→// RENDERING TYPES (Runtime/Calculated)
    60→// These types are computed when data loads and used by the canvas.
    61→// Never persisted.
    62→// ─────────────────────────────────────────────────────────────
    63→
    64→export type TaskColor = 'blue' | 'orange' | 'gray';
    65→
    66→export interface TaskRender {
    67→  id: string;              // Same as Task.id
    68→  trainIndex: number;      // Y position (0-based index in trains array)
    69→  startDay: number;        // X position (days since meta.startDate)
    70→  duration: number;        // Width (days)
    71→  color: TaskColor;        // Derived from Task.type
    72→  hasConflict: boolean;    // Passthrough from Task
    73→  type: TaskType;          // For label display in MicroLayer
    74→}
    75→
    76→export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
    77→  maintenance: 'blue',
    78→  overhaul: 'orange',
    79→  inspection: 'gray',
    80→};
    81→
    82→// ─────────────────────────────────────────────────────────────
    83→// CANVAS CONFIGURATION
    84→// ─────────────────────────────────────────────────────────────
    85→
    86→export interface ViewConfig {
    87→  pxPerDay: number;        // Pixels per day (X scale)
    88→  pxPerTrain: number;      // Pixels per train row (Y scale)
    89→  minZoom: number;         // Minimum zoom level
    90→  maxZoom: number;         // Maximum zoom level
    91→  zoomSensitivity: number; // Scroll sensitivity
    92→  lodThresholds: {
    93→    macro: number;         // Below this → MACRO view
    94→    micro: number;         // Above this → MICRO view
    95→  };
    96→}
    97→
    98→export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';
    99→
   100→export interface ViewportState {
   101→  zoom: number;
   102→  panX: number;
   103→  panY: number;
   104→  lod: LODLevel;
   105→}
   106→
   107→// ─────────────────────────────────────────────────────────────
   108→// DEFAULT VALUES
   109→// ─────────────────────────────────────────────────────────────
   110→
   111→export const DEFAULT_VIEW_CONFIG: ViewConfig = {
   112→  pxPerDay: 10,
   113→  pxPerTrain: 24,
   114→  minZoom: 0.1,
   115→  maxZoom: 5,
   116→  zoomSensitivity: 0.002,
   117→  lodThresholds: {
   118→    macro: 0.5,
   119→    micro: 2.0,
   120→  },
   121→};
   122→
   123→export const DEFAULT_DATASET_META: DatasetMeta = {
   124→  startDate: '2024-01-01',
   125→  trainCount: 50,
   126→  years: 10,
   127→};
   128→
   129→// ─────────────────────────────────────────────────────────────
   130→// FUTURE EXTENSIONS (Optional Fields)
   131→// These fields can be added without breaking existing code.
   132→// ─────────────────────────────────────────────────────────────
   133→
   134→// Extended Train (future)
   135→export interface TrainExtended extends Train {
   136→  carsCount?: number;
