   148→  status?: 'scheduled' | 'in-progress' | 'completed';
   149→}
   150→
   151→// Conflict as separate entity (future)
   152→export interface Conflict {
   153→  id: string;
   154→  taskIds: [string, string];
   155→  type: 'overlap' | 'resource' | 'dependency';
   156→  severity: 'low' | 'medium' | 'high';
